import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const x=JSON.parse('{"title":"钟鼓楼","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/drum-tower.md","filePath":"landmarks/drum-tower.md","lastUpdated":1784712887000}'),n={name:"landmarks/drum-tower.md"};function o(i,t,d,s,h,g){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="钟鼓楼" tabindex="-1">钟鼓楼 <a class="header-anchor" href="#钟鼓楼" aria-label="Permalink to &quot;钟鼓楼&quot;">​</a></h1><blockquote><p>&quot;晨钟暮鼓，老北京的时间记忆。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>钟鼓楼位于北京市东城区中轴线上，是元、明、清三代的报时中心。钟楼和鼓楼两座古建筑遥相对峙，气势雄伟，是北京中轴线的重要组成部分。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">9:00-17:00</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">钟楼10元，鼓楼20元，联票30元</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">1-1.5小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁2号线/8号线鼓楼大街站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区钟楼湾临字9号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="始建" tabindex="-1">始建 <a class="header-anchor" href="#始建" aria-label="Permalink to &quot;始建&quot;">​</a></h3><p>钟鼓楼始建于元至元九年（1272年），当时名为&quot;中心阁&quot;，后毁于火。明永乐十八年（1420年）重建。</p><h3 id="清代重修" tabindex="-1">清代重修 <a class="header-anchor" href="#清代重修" aria-label="Permalink to &quot;清代重修&quot;">​</a></h3><p>清乾隆十年（1745年），钟楼毁于大火，后重建。鼓楼的鼓和钟楼的钟均为乾隆年间重制。</p><h3 id="功能" tabindex="-1">功能 <a class="header-anchor" href="#功能" aria-label="Permalink to &quot;功能&quot;">​</a></h3><p>钟鼓楼是古代北京的报时中心，&quot;晨钟暮鼓&quot;是京城百姓生活的时间参照。</p><ul><li><strong>钟</strong>：夜间报时，每晚戌时（19-21点）敲响，共108响</li><li><strong>鼓</strong>：白天报时，每日定更（19点）和亮更（5点）击鼓</li></ul><h2 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h2><h3 id="鼓楼" tabindex="-1">鼓楼 <a class="header-anchor" href="#鼓楼" aria-label="Permalink to &quot;鼓楼&quot;">​</a></h3><p>鼓楼坐北朝南，高约47米，是北京市区现存最高的古建筑之一。</p><h4 id="结构" tabindex="-1">结构 <a class="header-anchor" href="#结构" aria-label="Permalink to &quot;结构&quot;">​</a></h4><ul><li><strong>台基</strong>：砖石结构，高4米</li><li><strong>楼身</strong>：木结构，重檐三滴水，灰筒瓦绿剪边</li><li><strong>高度</strong>：通高约47米</li><li><strong>面阔</strong>：五间，进深三间</li></ul><h4 id="鼓" tabindex="-1">鼓 <a class="header-anchor" href="#鼓" aria-label="Permalink to &quot;鼓&quot;">​</a></h4><p>鼓楼内原有25面鼓，其中1面主鼓，24面群鼓，代表二十四节气。现仅存1面主鼓，其余为复制品。</p><h3 id="钟楼" tabindex="-1">钟楼 <a class="header-anchor" href="#钟楼" aria-label="Permalink to &quot;钟楼&quot;">​</a></h3><p>钟楼位于鼓楼北约100米，坐北朝南，高约48米，是全北京的制高点。</p><h4 id="结构-1" tabindex="-1">结构 <a class="header-anchor" href="#结构-1" aria-label="Permalink to &quot;结构&quot;">​</a></h4><ul><li><strong>台基</strong>：砖石结构，高4米</li><li><strong>楼身</strong>：木结构，重檐歇山顶，黑筒瓦绿剪边</li><li><strong>高度</strong>：通高约48米</li><li><strong>特点</strong>：全砖石结构，坚固耐火</li></ul><h4 id="永乐大钟" tabindex="-1">永乐大钟 <a class="header-anchor" href="#永乐大钟" aria-label="Permalink to &quot;永乐大钟&quot;">​</a></h4><p>钟楼内悬挂的永乐大钟是钟楼的镇楼之宝：</p><ul><li><strong>铸造年代</strong>：明永乐十八年（1420年）</li><li><strong>重量</strong>：约63吨</li><li><strong>高度</strong>：约7米</li><li><strong>直径</strong>：约3.4米</li><li><strong>特点</strong>：钟身铸有梵文经咒，音质浑厚</li></ul><h2 id="击鼓表演" tabindex="-1">击鼓表演 <a class="header-anchor" href="#击鼓表演" aria-label="Permalink to &quot;击鼓表演&quot;">​</a></h2><p>鼓楼每天有击鼓表演，游客可以聆听古代报时的声音。</p><h3 id="表演时间" tabindex="-1">表演时间 <a class="header-anchor" href="#表演时间" aria-label="Permalink to &quot;表演时间&quot;">​</a></h3><ul><li><strong>上午</strong>：9:30、10:30、11:30</li><li><strong>下午</strong>：13:30、14:30、15:30、16:30</li></ul><h3 id="表演内容" tabindex="-1">表演内容 <a class="header-anchor" href="#表演内容" aria-label="Permalink to &quot;表演内容&quot;">​</a></h3><p>演员身着古装，按照古代击鼓仪式，击鼓报时，还原&quot;暮鼓&quot;场景。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>钟鼓楼游览（约1-1.5小时）</strong>：</p><p>鼓楼 → 登楼参观 → 观看击鼓表演 → 下楼 → 步行至钟楼 → 登楼参观 → 远眺北京中轴线</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">2号线/8号线鼓楼大街站G口</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">5路、60路、82路等鼓楼站</td></tr><tr><td style="text-align:left;">步行</td><td style="text-align:left;">从南锣鼓巷步行约15分钟</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>联票推荐</strong>：建议购买钟鼓楼联票，更划算</li><li><strong>击鼓表演</strong>：提前查看表演时间，别错过</li><li><strong>楼梯较陡</strong>：上下楼注意安全，楼梯较陡</li><li><strong>登楼视野</strong>：可远眺景山、北海、中轴线</li><li><strong>周边游览</strong>：可与南锣鼓巷、什刹海一起游览</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">南锣鼓巷</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">老北京胡同</td></tr><tr><td style="text-align:left;">什刹海</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">老北京风情</td></tr><tr><td style="text-align:left;">烟袋斜街</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">特色商业街</td></tr><tr><td style="text-align:left;">北海公园</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">皇家园林</td></tr><tr><td style="text-align:left;">景山公园</td><td style="text-align:center;">步行20分钟</td><td style="text-align:left;">俯瞰故宫</td></tr></tbody></table><h2 id="文化意义" tabindex="-1">文化意义 <a class="header-anchor" href="#文化意义" aria-label="Permalink to &quot;文化意义&quot;">​</a></h2><p>&quot;晨钟暮鼓&quot;是北京古城的重要标志，也是老北京生活的节奏。在古代，钟鼓声是京城百姓起居作息的时间信号。</p><p>如今，钟鼓楼虽然已经失去了报时功能，但作为北京中轴线的重要组成部分，它们见证了北京城的历史变迁，是北京文化的重要象征。</p><hr><p><strong>📍 地址</strong>：北京市东城区钟楼湾临字9号 <strong>📞 电话</strong>：010-84027869</p>',49)])])}const c=a(n,[["render",o]]);export{x as __pageData,c as default};
